      dma.set("kcomcd", scwin.hd_kcomcd);
      dma.set("bkNo", ed_bkNo.getValue());
      dma.set("seq", ds_containerDoorOrder.getCellData(ds_containerDoorOrder.getRowPosition(), "bkdoorseq"));
