scwin.f_Delete = async function () {
  let param1 = scwin.hd_kcomcd;
  let param2 = lc_cfs.getValue();
  sbm_bkCloseCheck.action = "/cm.zz.RetrieveComboCMD.do?sysCd=SeaExportBookingEBC&queryId=retrivebkCloseCheck&param1=" + param1 + "&param2=" + param2;
  await $c.sbm.execute($p, sbm_bkCloseCheck);
  if (ds_bkCloseCheck.getRowCount() > 0 && ds_bkCloseCheck.getCellData(0, "CODE") == "Y") {
    await $c.win.alert($p, "Bring to a close");
    return;
  }
  let errorChk = 0;
  for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
    if (ds_containerDoorOrder.getCellData(i, "sendDt") != "") {
      await $c.win.alert($p, "Order sended : Order No -> " + ds_containerDoorOrder.getCellData(i, "bkNo") + ",Seq -> " + ds_containerDoorOrder.getCellData(i, "bkdoorseq"));
      errorChk = 1;
    }
  }
  if (errorChk == 1) return;
  scwin.f_RetrieveBinding(dma_retrieve, "RetrieveBookingHbl");
  await $c.sbm.execute($p, sbm_retrievebookingHbl);
  if (ds_bookingHbl.getCellData(ds_bookingHbl.getRowPosition(), "hblno") != "undefined" && ds_bookingHbl.getRowCount() != 0) {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_041, ["House B/L", "delete"]);
    return;
  }
  let chk = await $c.win.confirm($p, E_MSG_CM_CRM_004);
  if (chk) {
    ds_containerBookingList.removeAll();
    scwin.f_RetrieveBinding(dma_retrieve, "RetrieveBookingHbl");
    await $c.sbm.execute($p, sbm_retrievebookingHbl);
    await $c.sbm.execute($p, sbm_delete);
    lc_cfs.setValue("");
    ds_containerBookingList.removeAll();
    ds_containerDoorOrder.removeAll();
    ds_containerDoorOrderQty.removeAll();
    ds_houseblList.removeAll();
    scwin.f_Set("INIT");
    lc_cfs.setValue("");
  }
};
scwin.f_orderSend = async function () {
  if (ds_containerDoorOrder.getCellData(ds_containerDoorOrder.getRowPosition(), "internalTyp") == "1") {
    if (ds_containerBookingList.getCellData(ds_containerBookingList.getRowPosition(), "itemCd") == "") {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Item"]);
      $c.gus.cfViewTab($p, 0);
      ed_itemCd.setFocus();
      return;
    }
    let errorChk = 0;
    let j = 0;
    for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
      if (ds_containerDoorOrder.getCellData(i, "chk") == "T") {
        j = j + 1;
      }
    }
    if (j == 0) errorChk = 1;
    for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
      if (ds_containerDoorOrder.getCellData(i, "chk") == "T") {
        let v_orderno = ds_containerDoorOrder.getCellData(i, "bkNo");
        let v_seq = ds_containerDoorOrder.getCellData(i, "bkdoorseq");
        let vk = scwin.hd_kcomcd;
        sbm_doorOrderQtyCheck.action = "/cm.zz.RetrieveComboCMD.do?sysCd=SeaExportBookingEBC&queryId=retrivedoorOrderQtyCheck&param1=" + vk + "&param2=" + v_orderno + "&param3=" + v_seq;
        await $c.sbm.execute($p, sbm_doorOrderQtyCheck);
        if (ds_doorOrderQtyCheck.getRowCount() > 0 && ds_doorOrderQtyCheck.getCellData(0, "CODE") == "0") {
          errorChk = 1;
          await $c.win.alert($p, "Door Order Qty is not exist: Order No -> " + v_orderno + ",Seq -> " + v_seq);
        }
      }
    }
    if (errorChk == 0) {
      for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
        if (ds_containerDoorOrder.getCellData(i, "chk") == "T") {
          ds_containerDoorOrder.setCellData(i, "kcomcd", scwin.hd_kcomcd);
          if (ds_containerDoorOrder.getCellData(i, "sendDt") == "") {
            ds_containerDoorOrder.setCellData(i, "orderType", 1);
          } else {
            ds_containerDoorOrder.setCellData(i, "orderType", 2);
          }
          ds_containerDoorOrder.setCellData(i, "inpid", scwin.userId);
        }
      }
      await $c.sbm.execute($p, sbm_saveOrderSend);
      scwin.f_Retrieve();
    }
  } else {
    await $c.win.alert($p, "Normal Type");
    return;
  }
};
