scwin.f_addRow = async function (disGubun) {
  switch (disGubun) {
    case 1:
      if (ed_bkNo.getValue() == "") {
        await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Booking Header"]);
      } else {
        ds_containerDoorOrder.insertRow();
        let rowPos = ds_containerDoorOrder.getRowPosition();
        let v_seq = (rowPos + 1).toString();
        let v_seqResult = $c.str.lpad($p, v_seq, "0", 2);
        ds_containerDoorOrder.setCellData(rowPos, "bkdoorseq", v_seqResult);
        ds_containerDoorOrder.setCellData(rowPos, "kcomcd", scwin.hd_kcomcd);
        ds_containerDoorOrder.setCellData(rowPos, "bkNo", ed_bkNo.getValue());
        ds_containerDoorOrder.setCellData(rowPos, "internalTyp", "1");
        ds_containerDoorOrder.setCellData(rowPos, "inpid", scwin.userId);
        ds_containerDoorOrder.setCellData(rowPos, "doordt", scwin.vCurDate + scwin.currentTime);
        gr_containerDoorOrder.setFocusedCell(rowPos, "doordt");
      }
      break;
    case 2:
      if (ed_bkNo.getValue() == "") {
        await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Booking Header"]);
      } else {
        if (ds_containerDoorOrder.getCellData(ds_containerDoorOrder.getRowPosition(), "bkdoorseq") == "" || ds_containerDoorOrder.getRowCount() == 0) {
          await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_049, ["Booking Door Order"]);
        } else {
          ds_containerDoorOrderQty.insertRow();
          let rowPos = ds_containerDoorOrderQty.getRowPosition();
          ds_containerDoorOrderQty.setCellData(rowPos, "kcomcd", scwin.hd_kcomcd);
          ds_containerDoorOrderQty.setCellData(rowPos, "bkNo", ed_bkNo.getValue());
          ds_containerDoorOrderQty.setCellData(rowPos, "bkdoorseq", ds_containerDoorOrder.getCellData(ds_containerDoorOrder.getRowPosition(), "bkdoorseq"));
          ds_containerDoorOrderQty.setCellData(rowPos, "inpid", scwin.userId);
          gr_containerDoorOrderQty.setFocusedCell(rowPos, "qtytype");
        }
      }
      break;
  }
};
scwin.f_deleteRow = async function (disGubun) {
  switch (disGubun) {
    case 1:
      if (ds_containerDoorOrderQty.getRowCount() > 0) {
        await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_041, ["Door Order Quantity Or Container", "delete"]);
      } else if (ds_containerDoorOrder.getCellData(ds_containerDoorOrder.getRowPosition(), "sendDt") != "") {
        await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_041, ["Order sended", "delete"]);
      } else {
        ds_containerDoorOrder.removeRow(ds_containerDoorOrder.getRowPosition());
      }
      break;
    case 2:
      ds_containerDoorOrderQty.removeRow(ds_containerDoorOrderQty.getRowPosition());
      break;
  }
};
scwin.f_cancelRow = function (disGubun) {
  switch (disGubun) {
    case 1:
      ds_containerDoorOrder.undoAll();
      ds_containerDoorOrderQty.undoAll();
      break;
    case 2:
      ds_containerDoorOrderQty.undoAll();
      break;
  }
};
scwin.f_validate = async function () {
  if (scwin.tabIndex == 0) {
    if (!(await scwin.f_BookingTabValidate())) {
      return false;
    }
  } else if (scwin.tabIndex == 1) {
    if (!(await scwin.f_DoorOrderTabValidate())) {
      return false;
    }
  }
  return true;
};
scwin.f_BookingTabValidate = async function () {
  let chk = await $c.gus.cfValidate($p, [udc_reDt, udc_bkEtd, udc_bkEta]);
  if (!chk) {
    return false;
  }
  if (udc_bkEtd.getValue() == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["ETD"]);
    udc_bkEtd.setFocus();
    return false;
  }
  if (udc_bkEta.getValue() != "") {
    if (!$c.gus.cfIsAfterDate($p, udc_bkEtd.getValue(), udc_bkEta.getValue())) {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_048, ["ETD", "ETA"]);
      udc_bkEtd.setFocus();
      return false;
    }
  }
  if (ed_custCd.getValue() == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Customer"]);
    ed_custCd.setFocus();
    return false;
  }
  if (ds_ctrtNo.getCellData(ds_ctrtNo.getRowPosition(), "ctrtNo") == "선택" || lc_contractno.getValue() == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Contract No"]);
    ed_custCd.setFocus();
    return false;
  }
  if (ed_dept.getValue() == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Department"]);
    ed_dept.setFocus();
    return false;
  }
  return true;
};
scwin.f_DoorOrderTabValidate = async function () {
  let msg = "[Booking] ";
  let chk = await $c.gus.cfValidate($p, [gr_containerDoorOrder]);
  if (!chk) {
    return false;
  }
  if (udc_bkEtd.getValue() == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, [msg + "ETD"]);
    return false;
  }
  if (udc_bkEta.getValue() != "") {
    if (!$c.gus.cfIsAfterDate($p, udc_bkEtd.getValue(), udc_bkEta.getValue())) {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_048, ["ETD", "ETA"]);
      udc_bkEtd.setFocus();
      return false;
    }
  }
  if (ed_custCd.getValue() == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, [msg + "Customer"]);
    return false;
  }
  if (ds_ctrtNo.getCellData(ds_ctrtNo.getRowPosition(), "ctrtNo") == "선택" || lc_contractno.getValue() == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, [msg + "Contract No"]);
    return false;
  }
  if (ed_dept.getValue() == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, [msg + "Department"]);
    return false;
  }
  for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
    if (ds_containerDoorOrder.getRowStatus(i) != "D") {
      if (ds_containerDoorOrder.getRowCount() > 0) {
        if (ds_containerDoorOrderQty.getRowCount() == 0) {
          await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Door Order Qty"]);
          return false;
        }
      }
    }
  }
  for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
    if (ds_containerDoorOrder.getCellData(i, "bkdoorseq") == "") {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Door Order Seq"]);
      gr_containerDoorOrder.setFocusedCell(i, "bkdoorseq");
      return false;
    }
  }
  for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
    if (ds_containerDoorOrder.getCellData(i, "doordt") == "") {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Container Order Date"]);
      gr_containerDoorOrder.setFocusedCell(i, "doordt");
      return false;
    }
  }
  for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
    if (ds_containerDoorOrder.getCellData(i, "transcd") == "") {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Container Order Trucker"]);
      gr_containerDoorOrder.setFocusedCell(i, "transcd");
      return false;
    }
  }
  for (let i = 0; i < ds_containerDoorOrderQty.getRowCount(); i++) {
    if (ds_containerDoorOrderQty.getCellData(i, "qtytype") == "") {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Door Order Container Type"]);
      gr_containerDoorOrderQty.setFocusedCell(i, "qtytype");
      return false;
    }
  }
  return true;
};
