scwin.gr_containerDoorOrder_onheaderclick = function (columnIndex, columnId) {
  if (columnId == "chk") {
    let allChecked = true;
    for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
      if (ds_containerDoorOrder.getCellData(i, "chk") != "T") {
        allChecked = false;
        break;
      }
    }
    if (!allChecked) {
      for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
        if (ds_containerDoorOrder.getCellData(i, "sendDt") == "") {
          ds_containerDoorOrder.setCellData(i, "chk", "T");
        }
      }
    } else {
      for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
        if (ds_containerDoorOrder.getCellData(i, "sendDt") == "") {
          ds_containerDoorOrder.setCellData(i, "chk", "F");
        }
      }
    }
  }
};
