scwin.lc_contractno_onchange = function (e) {
  if (scwin.statusFlag == "C" || scwin.statusFlag == "U") {
    if (ds_ctrtNo.getRowCount() == 0) ds_ctrtNo.insertRow();
    if (ds_ctrtNo.getCellData(ds_ctrtNo.getRowPosition(), "empNm") != "") {
      if (ed_salesCd.getValue() == "") {
        ed_salesCd.setValue(ds_ctrtNo.getCellData(ds_ctrtNo.getRowPosition(), "empNm"));
        scwin.f_OpenCommonPopUp('Salesman', 'T', 'F', 'F');
      }
    }
  }
};
scwin.ds_containerDoorOrder_onrowpositionchange = async function (rowIndex) {
  let v_kcomcd = ds_containerDoorOrder.getCellData(rowIndex, "kcomcd");
  let v_bkdoorseq = ds_containerDoorOrder.getCellData(rowIndex, "bkdoorseq");
  let v_bkNo = ds_containerDoorOrder.getCellData(rowIndex, "bkNo");
  if (rowIndex >= 0 && ds_containerDoorOrder.getRowStatus(rowIndex) != "C") {
    sbm_retrieveOrder.action = "/il.seaout.sobk.RetrieveBulkBookingOrderCMD.do?bkdoorseq=" + v_bkdoorseq + "&bkNo=" + v_bkNo + "&kcomcd=" + v_kcomcd;
    await $c.sbm.execute($p, sbm_retrieveOrder);
  } else if (ds_containerDoorOrder.getRowStatus(rowIndex) == "C") {
    let v_cnt = 0;
    for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
      if (ds_containerDoorOrder.getRowStatus(i) == "C") {
        v_cnt += 1;
      }
    }
    if (v_cnt == 1) {
      ds_containerDoorOrderQty.removeAll();
    }
  }
};
scwin.ds_containerBookingList_onloadcompleted = function (e) {
  if (ds_containerBookingList.getRowCount() != 0) {
    if (ds_containerBookingList.getCellData(ds_containerBookingList.getRowPosition(), "contractno") != "") {
      scwin.v_contractno = ds_containerBookingList.getCellData(ds_containerBookingList.getRowPosition(), "contractno");
      if (scwin.v_contractno == "NONE") {
        scwin.f_ContractInfo();
        ds_ctrtNo.removeAll();
        ds_ctrtNo.insertRow();
        ds_ctrtNo.setCellData(0, "ctrtNo", "NONE");
        lc_contractno.setSelectedIndex(0);
      } else {
        scwin.f_ContractInfo();
      }
    }
    ed_mtwgt.setValue(Number(ds_containerBookingList.getCellData(ds_containerBookingList.getRowPosition(), "wgt")) / 1000);
  }
};
